/**
 * Handle user created event — send welcome notification.
 */
private async handleUserCreated(event: UserCreatedEvent): Promise<void> {
  this.logger.info(`Sending welcome notification for user ${event.user.id}`);

  await this.sendNotification({
    recipient: event.user.email,
    subject: 'Welcome to TaskFlowPro!',
    body: `Hi ${event.user.name}, welcome to TaskFlowPro! Your account has been created.`,
    channel: 'email',
    notificationType: 'user_welcome',
    metadata: { userId: event.user.id },
  });
}

/**
 * Handle user updated event — notify user of profile changes.
 */
private async handleUserUpdated(event: UserUpdatedEvent): Promise<void> {
  this.logger.info(`Sending profile update notification for user ${event.user.id}`);

  const changeList = event.changes.join(', ');
  await this.sendNotification({
    recipient: event.user.email,
    subject: 'Profile Updated',
    body: `Your profile has been updated. Changed fields: ${changeList}.`,
    channel: 'email',
    notificationType: 'user_updated',
    metadata: { userId: event.user.id, changes: event.changes },
  });
}

